scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "OP291", compID : "gr_master:lobranCd" },
        { grpCd : "OP570", compID : "gr_master:cargoClsCd"},
        { grpCd : "LO102", compID : "gr_master:unitCd"},

    ];
    $c.data.setCommonCode(codeOptions, scwin.commonCodeCallBack);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

    }, {"delay":50});
};

scwin.commonCodeCallBack = function(){
    //작업예정일 설정(오늘일자);
    ica_wrkIntendStDt.setValue($c.date.getServerDateTime("yyyyMMdd"));
    ica_wrkIntendEndDt.setValue($c.date.getServerDateTime("yyyyMMdd"));
    acb_lobran.setValue($c.data.getMemInfo("loUpperLobranCd"));    
    acb_lobran.focus();

    // $p.setTimeout(function() {
    //     ica_wrkIntendStDt.setValue("20100101");
    //     ica_wrkIntendEndDt.setValue("20101101");

    //     acb_lobran.setValue("6AA");
    // }, {"delay":50});

};

//-------------------------------------------------------------------------
// RETRIEVE;
//-------------------------------------------------------------------------
scwin.f_retrieve = async function () {

    // ds_search.removeAll();
    // ds_search.insertRow();

    ds_search.set("lobranCd", acb_lobran.getValue());
    ds_search.set("wrkIntendStDt", ica_wrkIntendStDt.getValue());
    ds_search.set("wrkIntendEndDt", ica_wrkIntendEndDt.getValue());

    if (!await $c.gus.cfValidate([ica_wrkIntendStDt, ica_wrkIntendEndDt])) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(ica_wrkIntendStDt.getValue(), ica_wrkIntendEndDt.getValue())) {
        await $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ica_wrkIntendStDt.focus();
        return;
    }

    $c.sbm.execute(sbm_retrieve);

};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (){
    var modifyRowCnt = ds_master.getModifiedIndex().length
    if (!(modifyRowCnt > 0)) {
        await $c.win.alert("변경된 사항이 없습니다.");
    } else {
        // Grid의 필수 입력 항목에 대해서 Check 한다.
        if (!await $c.gus.cfValidate([gr_master])) {
            return;
        }

        for (var i = 0 ; i < ds_master.getRowCount() ; i++) {
            if (ds_master.getCellData(i, "wrkStIntendDt") > ds_master.getCellData(i, "wrkEndIntendDt") ) {
                await $c.gus.cfAlertMsg((i+1) + "번째 작업기간의 시작예정일이 종료예정일보다 큽니다.");
                ds_master.setRowPosition(i);
                return;
            }

            if (ds_master.getCellData(i, "wrkIntendDt") == "" || ds_master.getCellData(i, "lobranCd") == "" 
             || ds_master.getCellData(i, "pierNm") == "") {
                    await $c.gus.cfAlertMsg((i+1) + "번째 작업예정일/점소/부두 를 입력해주세요.");
                    ds_master.setRowPosition(i);
                    return;
            }
        }
        if (await $c.win.confirm("저장하시겠습니까?")){       
            $c.sbm.execute(sbm_save);
        }
    }
};


//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.addRow = function () {     
    var rowIdx = ds_master.insertRow();
    ds_master.setRowPosition(rowIdx);
    // await $c.win.alert( ds_out.ExportData( 1, ds_out.CountRow , true ) ) ; 
};

scwin.f_ResetCon = function (){
    acb_lobran.setValue($c.data.getMemInfo("loUpperLobranCd"));    
    ica_wrkIntendStDt.setValue($c.date.getServerDateTime("yyyyMMdd"));
    ica_wrkIntendEndDt.setValue($c.date.getServerDateTime("yyyyMMdd"));
    acb_lobran.focus();
};

scwin.delFormatter = function(a,b,c,d,e,f,g){
    if (a == "0"){
        return "아니오";
    } else {
        return "예";
    }
};

scwin.excelDown = function(){
    //                     //sheet명       , 저장파일명            , 저장 다이얼로그
    // cfGridToExcel(gr_master, "지사부두별작업예정정보" , "지사부두별작업예정정보.xls" , 4+8+16);
    const infoArr = [];
    const options = {
        fileName : "지사부두별작업예정정보.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: "지사부두별작업예정정보",
        type : "1",
        // startRowIndex: 2,
        // removeColumns: "0,21",
        // hiddenVisible : true,
        // useSubTotal :"true", 
        // useSubTotalData  : "true",
        // oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
        // evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
    };
    $c.data.downloadGridViewExcel(gr_master, options, infoArr);
};

